  'ganzhou/pavilion': ('Úc Cô Đình', 'Từng được các thi sĩ thời Tống ca ngợi, đình đài này nhìn ra nơi giao thoa của dòng sông.'),
  'ganzhou/star': ('Vạn lý Trường chinh', 'Cuộc Vạn lý Trường chinh của Hồng quân đã bắt đầu từ chính thành phố này.'),
  'putian/shrine': ('Đền thờ Mẫu Tổ', 'Nữ thần Mẫu Tổ, vị thần bảo hộ ngư dân, đã sinh ra tại đây và ngôi đền thờ chính của bà tọa lạc trên đảo Mi Châu.'),
  'putian/lychee': ('Vườn vải', 'Những gốc vải nghìn năm tuổi đã mang lại cho thành phố này danh xưng là xứ sở của vải thiều.'),
  'putian/shoe': ('Thủ phủ giày dép', 'Một phần lớn sản lượng giày thể thao trên thế giới được sản xuất tại các xưởng ở thành phố này.'),
  'putian/wave': ('Đảo Mi Châu', 'Hòn đảo này nổi tiếng với những bãi biển thơ mộng và các lễ hội đền chùa đặc sắc, có thể đến đây bằng phà.'),
  'mudanjiang/snow': ('Làng Tuyết', 'Ngôi làng cổ tích này khoác lên mình lớp tuyết dày trắng xóa, tỏa sáng rực rỡ trong những ngày đông.'),
  'mudanjiang/lake': ('Hồ Kính Bạc', 'Đây là một hồ nước hình thành từ núi lửa, nơi có thác Điếu Thủy Lâu vẫn đổ nước ngay cả trong mùa đông giá rét.'),
  'mudanjiang/tiger': ('Công viên Hổ Siberia', 'Đây là một trong những khu bảo tồn hổ Siberia lớn nhất trên thế giới.'),
  'mudanjiang/ski': ('Mùa trượt tuyết', 'Mùa đông dài với tuyết phủ dày đặc đã đưa khu vực này trở thành điểm đến không thể bỏ qua của những người yêu trượt tuyết.'),
  'changzhou/dino': ('Công viên Khủng long', 'Công viên chủ đề về khủng long nổi tiếng nhất Trung Quốc này là biểu tượng du lịch gia đình của thành phố.'),
  'changzhou/pagoda': ('Chùa Thiên Ninh', 'Với chiều cao 153 mét, đây là ngôi chùa cao nhất thế giới tọa lạc ngay trung tâm thành phố.'),
  'changzhou/comb': ('Nghề làm lược', 'Những chiếc lược Thường Châu với lịch sử ngàn năm từng là món quà quý giá dâng lên cung đình.'),
  'changzhou/canal': ('Đại Vận Hà', 'Dọc theo bờ kênh là nơi du khách thường tản bộ để ngắm nhìn những khu phố cổ và ánh đèn đêm lung linh.'),
  'shaoxing/wine': ('Rượu Thiệu Hưng', 'Loại rượu gạo vàng trứ danh trong ẩm thực Trung Hoa này đã được ủ tại đây suốt hàng ngàn năm qua.'),
  'shaoxing/bridge': ('Cầu đá cổ', 'Với hệ thống kênh rạch chằng chịt, Thiệu Hưng hiện vẫn lưu giữ hàng trăm cây cầu đá vòm cổ kính.'),
  'shaoxing/pen': ('Cái nôi thư pháp', 'Lan Đình của thư pháp gia Vương Hy Chi được coi là thánh địa của nghệ thuật thư pháp Trung Hoa.'),
  'shaoxing/boat': ('Thuyền Ô Bồng', 'Những chiếc thuyền Ô Bồng được chèo bằng chân là phương tiện di chuyển cổ điển trên các con kênh tại đây.'),
  'bengbu/shell': ('Bến Ngọc Trai', 'Tên gọi của thành phố có nghĩa là \'bến hàu\', nơi từng nổi tiếng với những viên ngọc trai quý giá từ sông Hoài.'),
  'bengbu/train': ('Cửa ngõ đường sắt', 'Thành phố này phát triển mạnh mẽ nhờ vị trí là điểm giao cắt quan trọng của tuyến đường sắt Bắc - Nam qua sông Hoài.'),
  'bengbu/river': ('Sông Hoài', 'Đây chính là dòng sông được coi là ranh giới tự nhiên phân chia hai miền Nam - Bắc của Trung Quốc.'),
  'bengbu/blossom': ('Lễ hội hoa xuân', 'Mỗi độ xuân về, các công viên ven sông lại rực rỡ sắc hoa trong những lễ hội truyền thống.'),
  'jiujiang/mountain': ('Núi Lư', 'Những đỉnh núi mờ sương của Lư Sơn đã được UNESCO công nhận là di sản thế giới và là nguồn cảm hứng bất tận cho thi ca, hội họa.'),
  'jiujiang/tea': ('Trà Vân Vụ', 'Loại trà Vân Vụ trồng trên sườn núi Lư là một trong những loại trà tinh tế và thượng hạng nhất Trung Quốc.'),
  'jiujiang/lake': ('Hồ Bà Dương', 'Hồ nước ngọt lớn nhất Trung Quốc này là nơi trú ngụ của hàng ngàn con sếu mỗi khi đông về.'),
  'jiujiang/scroll': ('Thành phố thi ca', 'Cửa ngõ ven sông này từng là nơi lưu dấu những vần thơ bất hủ của các thi hào như Bạch Cư Dị và Tô Thức.'),
  'quanzhou/ship': ('Con đường tơ lụa trên biển', 'Từng được Marco Polo gọi là \'Zayton\', đây là cảng biển sầm uất nhất thế giới thời trung cổ và hiện là di sản UNESCO.'),
  'quanzhou/mosque': ('Thánh đường Thanh Tịnh', 'Được xây dựng từ năm 1009, đây là một trong những thánh đường Hồi giáo cổ xưa nhất tại Trung Quốc.'),
  'quanzhou/puppet': ('Múa rối dây', 'Nghệ thuật múa rối dây Tuyền Châu là một truyền thống sân khấu đã có lịch sử hàng ngàn năm.'),
  'quanzhou/tea': ('Trà Thiết Quan Âm', 'Loại trà ô long nổi tiếng thế giới đến từ vùng An Khê lân cận này còn được gọi là \'Nữ thần sắt\'.'),
  'beijing/great-wall': ('Vạn Lý Trường Thành', 'Công trình phòng thủ dài nhất thế giới với hơn 20.000 km, trong đó đoạn Bát Đạt Lĩnh gần Bắc Kinh là nơi thu hút đông đảo du khách nhất.'),
  'beijing/temple': ('Thiên Đàn', 'Nơi các hoàng đế nhà Minh và Thanh từng cầu nguyện cho mùa màng bội thu, nổi tiếng với kiến trúc mái vòm xanh không dùng một chiếc đinh nào.'),
  'beijing/pagoda': ('Chùa Thiên Ninh', 'Ngôi chùa gạch 13 tầng từ thời nhà Liêu này là một trong những công trình cổ nhất còn sót lại, chứng nhân cho lịch sử ngàn năm của Bắc Kinh.'),
  'beijing/opera': ('Kinh kịch', 'Loại hình nghệ thuật truyền thống kết hợp ca hát, võ thuật và nhào lộn, nơi mỗi màu sắc trên mặt nạ đều ẩn chứa tính cách riêng của nhân vật.'),
};
